def solve(vals_str, target, k):
    from collections import defaultdict, deque
    vals = vals_str.split()
    if not vals or vals[0] == 'null': return ''
    nodes = [int(v) if v != 'null' else None for v in vals]
    adj = defaultdict(list)
    for i, v in enumerate(nodes):
        if v is None: continue
        left_i = 2*i+1; right_i = 2*i+2
        if left_i < len(nodes) and nodes[left_i] is not None:
            adj[v].append(nodes[left_i]); adj[nodes[left_i]].append(v)
        if right_i < len(nodes) and nodes[right_i] is not None:
            adj[v].append(nodes[right_i]); adj[nodes[right_i]].append(v)
    visited = {target}; q = deque([target]); dist = 0
    while q and dist < k:
        for _ in range(len(q)):
            node = q.popleft()
            for nb in adj[node]:
                if nb not in visited:
                    visited.add(nb); q.append(nb)
        dist += 1
    return ' '.join(map(str, sorted(q)))

